B.Ly=new A.bd(B.c1,[B.Hy,B.Ik,B.JM,'\ud83d\udcb8 To transfer money:\n\n1\ufe0f\u20e3 On the Home screen tap "Transfers"\n2\ufe0f\u20e3 Enter the recipient\'s phone number\n3\ufe0f\u20e3 Enter the amount to send\n4\ufe0f\u20e3 Tap "Send"\n5\ufe0f\u20e3 Enter your secret PIN to confirm\n\n\u2705 Transfer is instant between accounts!\n\u26a0\ufe0f Double-check the number before confirming.','\ud83d\udcb8 \u0644\u062a\u062d\u0648\u064a\u0644 \u0627\u0644\u0623\u0645\u0648\u0627\u0644:\n\n1\ufe0f\u20e3 \u0641\u064a \u0627\u0644\u0635\u0641\u062d\u0629 \u0627\u0644\u0631\u0626\u064a\u0633\u064a\u0629 \u0627\u0636\u063a\u0637 \u0639\u0644\u0649 "\u062a\u062d\u0648\u064a\u0644"\n2\ufe0f\u20e3 \u0623\u062f\u062e\u0644 \u0631\u0642\u0645 \u0647\u0627\u062a\u0641 \u0627\u0644\u0645\u0633\u062a\u0644\u0645\n3\ufe0f\u20e3 \u0623\u062f\u062e\u0644 \u0627\u0644\u0645\u0628\u0644\u063a \u0627\u0644\u0645\u0631\u0627\u062f \u0625\u0631\u0633\u0627\u0644\u0647\n4\ufe0f\u20e3 \u0627\u0636\u063a\u0637 "\u0625\u0631\u0633\u0627\u0644"\n5\ufe0f\u20e3 \u0623\u062f\u062e\u0644 \u0631\u0642\u0645\u0643 \u0627\u0644\u0633\u0631\u064a \u0644\u0644\u062a\u0623\u0643\u064a\u062f\n\n\u2705 \u0627\u0644\u062a\u062d\u0648\u064a\u0644 \u064a\u062a\u0645 \u0641\u0648\u0631\u0627\u064b \u0628\u064a\u0646 \u0627\u0644\u062d\u0633\u0627\u0628\u0627\u062a!\n\u26a0\ufe0f \u062a\u0623\u0643\u062f \u0645\u0646 \u0631\u0642\u0645 \u0627\u0644\u0645\u0633\u062a\u0644\u0645 \u0642\u0628\u0644 \u0627\u0644\u062a\u0623\u0643\u064a\u062f.','\ud83d\udcb8 Pour transf\xe9rer de l\'argent:\n\n1\ufe0f\u20e3 Sur l\'accueil appuyez "Transferts"\n2\ufe0f\u20e3 Entrez le num\xe9ro de t\xe9l\xe9phone du destinataire\n3\ufe0f\u20e3 Entrez le montant \xe0 envoyer\n4\ufe0f\u20e3 Appuyez "Envoyer"\n5\ufe0f\u20e3 Entrez votre code PIN pour confirmer\n\n\u2705 Transfert instantan\xe9 entre comptes!\n\u26a0\ufe0f V\xe9rifiez bien le num\xe9ro avant de confirmer.'],t.EU)
